Certainly! A MERN (MongoDB, Express.js, React.js, Node.js) stack is great for building a full-stack web application. For a room management system, we can create a simple application where you can add, update, delete, and list rooms. Let's break it down into components:

### 1. Backend (Node.js + Express.js)

First, let's set up the backend server using Express.js.

#### Step 1: Install Dependencies

```bash
npm init -y
npm install express mongoose body-parser cors
```

#### Step 2: Create `server.js`

```javascript
const express = require('express');
const mongoose = require('mongoose');
const bodyParser = require('body-parser');
const cors = require('cors');

const app = express();
app.use(bodyParser.json());
app.use(cors());

// Connect to MongoDB
mongoose.connect('mongodb://localhost:27017/room-management', {
    useNewUrlParser: true,
    useUnifiedTopology: true
});

// Define Room Schema
const RoomSchema = new mongoose.Schema({
    name: { type: String, required: true },
    capacity: { type: Number, required: true }
});

const Room = mongoose.model('Room', RoomSchema);

// Routes
app.get('/rooms', async (req, res) => {
    const rooms = await Room.find();
    res.send(rooms);
});

app.post('/rooms', async (req, res) => {
    const { name, capacity } = req.body;
    const room = new Room({ name, capacity });
    await room.save();
    res.status(201).send(room);
});

app.put('/rooms/:id', async (req, res) => {
    const { id } = req.params;
    const { name, capacity } = req.body;
    const updatedRoom = await Room.findByIdAndUpdate(id, { name, capacity }, { new: true });
    if (!updatedRoom) return res.status(404).send('Room not found');
    res.send(updatedRoom);
});

app.delete('/rooms/:id', async (req, res) => {
    const { id } = req.params;
    const deletedRoom = await Room.findByIdAndDelete(id);
    if (!deletedRoom) return res.status(404).send('Room not found');
    res.send(deletedRoom);
});

const PORT = process.env.PORT || 5000;
app.listen(PORT, () => console.log(`Server running on port ${PORT}`));

